code = """import json

# Load both datasets
with open(locals()['var_functions.query_db:0'], 'r') as f:
    funding = json.load(f)

with open(locals()['var_functions.query_db:16'], 'r') as f:
    docs = json.load(f)

# Find FEMA/Emergency projects in funding data
fema_projects = []
for rec in funding:
    name_upper = rec.get('Project_Name', '').upper()
    if 'FEMA' in name_upper or 'EMERGENCY' in name_upper:
        fema_projects.append({
            'name': rec.get('Project_Name'),
            'source': rec.get('Funding_Source'),
            'amount': int(rec.get('Amount', 0))
        })

# For each FEMA project, try to find status in documents
final_list = []
for proj in fema_projects:
    status = 'Unknown'
    # Simple heuristic based on document text
    for doc in docs:
        text = doc.get('text', '').lower()
        base_name = proj['name'].split(' (')[0].lower()
        if base_name in text:
            if 'completed' in text:
                status = 'completed'
            elif 'construction' in text:
                status = 'construction'
            elif 'design' in text:
                status = 'design'
            break
    
    final_list.append({
        'Project_Name': proj['name'],
        'Funding_Source': proj['source'],
        'Amount': proj['amount'],
        'Status': status
    })

print('__RESULT__:')
print(json.dumps(final_list))"""

